  <line x1="70" y1="90" x2="650" y2="90" stroke="#27272a" stroke-width="1" stroke-dasharray="3,3"/>
  <rect x="140" y="240" width="70" height="95" fill="#4ade80"/>
  <text x="175" y="228" fill="#4ade80" font-family="sans-serif" font-size="15" font-weight="700" text-anchor="middle">0.156</text>
  <text x="175" y="355" fill="#a1a1aa" font-family="sans-serif" font-size="13" text-anchor="middle">6/30</text>
  <rect x="290" y="150" width="70" height="185" fill="#4ade80"/>
  <text x="325" y="138" fill="#4ade80" font-family="sans-serif" font-size="15" font-weight="700" text-anchor="middle">0.25</text>
  <text x="325" y="355" fill="#a1a1aa" font-family="sans-serif" font-size="13" text-anchor="middle">7/9</text>
  <rect x="440" y="153" width="70" height="182" fill="#4ade80" opacity="0.85"/>
